scwin.f_SetDefaultData = function () {
  ica_wrkDtSt.setValue(scwin.vQryStDt); // 운송일자시작		
  ica_wrkDtEnd.setValue(scwin.vQryEndDt); // 운송일자종료
  ica_pchsIntendDt.setValue(scwin.vCurDate);
  ; // 매입예정일자		
  //cfSetIMEModeActiveObjects([ed_wrkPlNm, ed_pchsDeptNm, ed_pchsClntNm, ed_admitPicNm, ed_rmk]);  // IME 한글 처리
  $c.gus.cfDisableObjects($p, [ica_pchsIntendDt, ed_rmk, ed_certiNo, btn_certiNo, ed_hid_rmk]);
  //lc_pchsAdmitClsCd.MaxLength = "50";		
  lc_pchsAdmitClsCd.setSelectedIndex(0);
  ed_pchsClntNo.focus();
};

//-------------------------------------------------------------------------
// 철송비용승인(일자별) 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveDateEachRailroadCostList = async function () {
  // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
  var chk = await $c.gus.cfValidate($p, [ed_pchsClntNo, ica_wrkDtSt, ica_wrkDtEnd, ed_pchsClntNo]);
  if (!chk) {
    return;
  }
  var chkDate = await $c.gus.cfIsAfterDate($p, ica_wrkDtSt.getValue(), ica_wrkDtEnd.getValue());
  if (!chkDate) {
    $c.win.alert($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
    ica_wrkDtSt.focus();
    return;
  }

  //tr_searchDateEachRailroadCostList.post();
  $c.sbm.execute($p, sbm_searchDateEachRailroadCostList);
};

